from __future__ import annotations
from dataclasses import dataclass, field
from typing import Dict, List, Optional, Tuple
import unittest


# ---------------------------------------------------------------------------
# Domain Models
# ---------------------------------------------------------------------------

@dataclass
class Expense:
    """Represents a single expense entry."""
    category: str
    amount: float
    description: str = ""

    def __post_init__(self):
        if self.amount < 0:
            raise ValueError("Expense amount cannot be negative")
        if not self.category or not self.category.strip():
            raise ValueError("Category cannot be empty")
        self.category = self.category.strip().lower()


@dataclass
class UserAccount:
    """Represents a user in the shared budget system."""
    username: str
    expenses: List[Expense] = field(default_factory=list)

    def add_expense(self, category: str, amount: float, description: str = "") -> Expense:
        expense = Expense(category=category, amount=amount, description=description)
        self.expenses.append(expense)
        return expense

    def total_expenses(self) -> float:
        return sum(e.amount for e in self.expenses)

    def expenses_by_category(self) -> Dict[str, float]:
        result: Dict[str, float] = {}
        for e in self.expenses:
            result[e.category] = result.get(e.category, 0.0) + e.amount
        return result


@dataclass
class BudgetCategory:
    """Budget limit for a specific category."""
    name: str
    limit: float

    def __post_init__(self):
        if self.limit < 0:
            raise ValueError("Budget limit cannot be negative")
        self.name = self.name.strip().lower()


# ---------------------------------------------------------------------------
# Core System
# ---------------------------------------------------------------------------

class MultiAgentBudgetOptimizer:
    """
    Collaborative budget management system for multiple users.
    Supports expense tracking, budget limits, dashboards, and optimization.
    """

    def __init__(self, group_name: str = "Default Group"):
        self.group_name: str = group_name
        self.users: Dict[str, UserAccount] = {}
        self.budget_limits: Dict[str, BudgetCategory] = {}
        self.financial_goal: float = 0.0

    # --- User Management ---

    def add_user(self, username: str) -> UserAccount:
        if not username or not username.strip():
            raise ValueError("Username cannot be empty")
        username = username.strip()
        if username in self.users:
            raise ValueError(f"User '{username}' already exists")
        account = UserAccount(username=username)
        self.users[username] = account
        return account

    def get_user(self, username: str) -> UserAccount:
        if username not in self.users:
            raise KeyError(f"User '{username}' not found")
        return self.users[username]

    def remove_user(self, username: str) -> None:
        if username not in self.users:
            raise KeyError(f"User '{username}' not found")
        del self.users[username]

    # --- Expense Management ---

    def add_expense(self, username: str, category: str, amount: float,
                    description: str = "") -> Expense:
        user = self.get_user(username)
        return user.add_expense(category, amount, description)

    # --- Budget Limits ---

    def set_budget_limit(self, category: str, limit: float) -> BudgetCategory:
        budget = BudgetCategory(name=category, limit=limit)
        self.budget_limits[budget.name] = budget
        return budget

    def adjust_budget_limit(self, category: str, new_limit: float) -> BudgetCategory:
        category = category.strip().lower()
        if category not in self.budget_limits:
            raise KeyError(f"No budget set for category '{category}'")
        self.budget_limits[category].limit = new_limit
        return self.budget_limits[category]

    def get_budget_limit(self, category: str) -> Optional[BudgetCategory]:
        return self.budget_limits.get(category.strip().lower())

    # --- Financial Goal ---

    def set_financial_goal(self, goal: float) -> None:
        if goal < 0:
            raise ValueError("Financial goal cannot be negative")
        self.financial_goal = goal

    # --- Dashboard & Summaries ---

    def total_group_expenses(self) -> float:
        return sum(user.total_expenses() for user in self.users.values())

    def total_budget(self) -> float:
        return sum(b.limit for b in self.budget_limits.values())

    def remaining_budget(self) -> float:
        return self.total_budget() - self.total_group_expenses()

    def group_expenses_by_category(self) -> Dict[str, float]:
        result: Dict[str, float] = {}
        for user in self.users.values():
            for e in user.expenses:
                result[e.category] = result.get(e.category, 0.0) + e.amount
        return result

    def individual_contributions(self) -> Dict[str, float]:
        return {name: user.total_expenses() for name, user in self.users.items()}

    def category_remaining(self) -> Dict[str, float]:
        """Remaining budget per category."""
        expenses = self.group_expenses_by_category()
        result: Dict[str, float] = {}
        for cat, budget in self.budget_limits.items():
            spent = expenses.get(cat, 0.0)
            result[cat] = budget.limit - spent
        return result

    def get_dashboard(self) -> Dict:
        """Returns a comprehensive dashboard summary."""
        return {
            "group_name": self.group_name,
            "total_budget": self.total_budget(),
            "total_expenses": self.total_group_expenses(),
            "remaining_budget": self.remaining_budget(),
            "financial_goal": self.financial_goal,
            "on_track": self.total_group_expenses() <= self.total_budget(),
            "individual_contributions": self.individual_contributions(),
            "expenses_by_category": self.group_expenses_by_category(),
            "category_remaining": self.category_remaining(),
            "budget_limits": {k: v.limit for k, v in self.budget_limits.items()},
        }

    # --- Optimization Engine ---

    def get_over_budget_categories(self) -> Dict[str, float]:
        """Returns categories that exceed their budget limit with the overage amount."""
        expenses = self.group_expenses_by_category()
        over = {}
        for cat, budget in self.budget_limits.items():
            spent = expenses.get(cat, 0.0)
            if spent > budget.limit:
                over[cat] = spent - budget.limit
        return over

    def get_under_budget_categories(self) -> Dict[str, float]:
        """Returns categories under budget with remaining amount."""
        expenses = self.group_expenses_by_category()
        under = {}
        for cat, budget in self.budget_limits.items():
            spent = expenses.get(cat, 0.0)
            if spent < budget.limit:
                under[cat] = budget.limit - spent
        return under

    def suggest_reallocations(self) -> List[Dict]:
        """
        Suggest fund reallocations from under-budget to over-budget categories.
        """
        over = self.get_over_budget_categories()
        under = self.get_under_budget_categories()

        if not over or not under:
            return []

        suggestions = []
        over_items = sorted(over.items(), key=lambda x: x[1], reverse=True)
        under_items = sorted(under.items(), key=lambda x: x[1], reverse=True)

        for over_cat, over_amount in over_items:
            remaining_need = over_amount
            for i, (under_cat, under_amount) in enumerate(under_items):
                if remaining_need <= 0 or under_amount <= 0:
                    break
                transfer = min(remaining_need, under_amount)
                suggestions.append({
                    "action": "reallocate",
                    "from_category": under_cat,
                    "to_category": over_cat,
                    "amount": round(transfer, 2),
                    "reason": (f"Transfer ${transfer:.2f} from '{under_cat}' "
                               f"(under budget) to '{over_cat}' (over budget)")
                })
                remaining_need -= transfer
                under_items[i] = (under_cat, under_amount - transfer)

        return suggestions

    def suggest_expense_reductions(self) -> List[Dict]:
        """
        Suggest expense reductions for users spending above average in
        over-budget categories.
        """
        over = self.get_over_budget_categories()
        if not over:
            return []

        suggestions = []
        num_users = len(self.users)
        if num_users == 0:
            return []

        for cat in over:
            user_spending: List[Tuple[str, float]] = []
            for name, user in self.users.items():
                cat_total = sum(e.amount for e in user.expenses if e.category == cat)
                if cat_total > 0:
                    user_spending.append((name, cat_total))

            if not user_spending:
                continue

            avg = sum(s for _, s in user_spending) / len(user_spending)
            for name, spent in user_spending:
                if spent > avg:
                    reduction = round(spent - avg, 2)
                    suggestions.append({
                        "action": "reduce",
                        "user": name,
                        "category": cat,
                        "current_spending": round(spent, 2),
                        "suggested_spending": round(avg, 2),
                        "reduction_amount": reduction,
                        "reason": (f"'{name}' spends ${spent:.2f} in '{cat}', "
                                   f"which is ${reduction:.2f} above the group average "
                                   f"of ${avg:.2f}")
                    })

        return suggestions

    def optimize(self) -> Dict:
        """
        Run full collaborative optimization and return all suggestions.
        """
        dashboard = self.get_dashboard()
        reallocations = self.suggest_reallocations()
        reductions = self.suggest_expense_reductions()

        goal_gap = 0.0
        if self.financial_goal > 0:
            goal_gap = max(0.0, self.total_group_expenses() - self.financial_goal)

        return {
            "dashboard": dashboard,
            "over_budget_categories": self.get_over_budget_categories(),
            "under_budget_categories": self.get_under_budget_categories(),
            "reallocation_suggestions": reallocations,
            "reduction_suggestions": reductions,
            "goal_gap": round(goal_gap, 2),
            "summary": self._build_summary(reallocations, reductions, goal_gap),
        }

    def _build_summary(self, reallocations: List[Dict],
                       reductions: List[Dict], goal_gap: float) -> str:
        lines = []
        if not reallocations and not reductions and goal_gap == 0:
            lines.append("Budget is on track. No optimization needed.")
            return "\n".join(lines)

        if goal_gap > 0:
            lines.append(
                f"The group is ${goal_gap:.2f} over the financial goal of "
                f"${self.financial_goal:.2f}.")

        if reallocations:
            lines.append(f"{len(reallocations)} reallocation(s) suggested:")
            for s in reallocations:
                lines.append(f"  - {s['reason']}")

        if reductions:
            lines.append(f"{len(reductions)} spending reduction(s) suggested:")
            for s in reductions:
                lines.append(f"  - {s['reason']}")

        return "\n".join(lines)


