            self.optimizer.add_expense("Alice", "misc", 10.0)
        self.assertEqual(self.optimizer.total_group_expenses(), 1000.0)

    def test_float_precision(self):
        self.optimizer.add_user("Alice")
        self.optimizer.set_budget_limit("groceries", 100.0)
        self.optimizer.add_expense("Alice", "groceries", 33.33)
        self.optimizer.add_expense("Alice", "groceries", 33.33)
        self.optimizer.add_expense("Alice", "groceries", 33.34)
        self.assertAlmostEqual(self.optimizer.total_group_expenses(), 100.0, places=2)

    def test_user_with_no_expenses(self):
        self.optimizer.add_user("Alice")
