        self.optimizer.add_expense("Alice", "groceries", 50.0)
        contributions = self.optimizer.individual_contributions()
        self.assertEqual(contributions["Bob"], 0.0)

    def test_category_with_no_budget_limit(self):
        self.optimizer.add_user("Alice")
        self.optimizer.add_expense("Alice", "travel", 500.0)
        over = self.optimizer.get_over_budget_categories()
        self.assertNotIn("travel", over)

    def test_reallocation_partial_coverage(self):
        self.optimizer.add_user("Alice")
        self.optimizer.set_budget_limit("groceries", 100.0)
        self.optimizer.set_budget_limit("entertainment", 200.0)
        self.optimizer.add_expense("Alice", "groceries", 200.0)
        self.optimizer.add_expense("Alice", "entertainment", 180.0)
        suggestions = self.optimizer.suggest_reallocations()
        total_reallocated = sum(s["amount"] for s in suggestions)
        self.assertLessEqual(total_reallocated, 20.0)

    def test_multiple_categories_over_budget(self):
        self.optimizer.add_user("Alice")
        self.optimizer.set_budget_limit("groceries", 50.0)
        self.optimizer.set_budget_limit("entertainment", 30.0)
        self.optimizer.set_budget_limit("utilities", 200.0)
        self.optimizer.add_expense("Alice", "groceries", 80.0)
        self.optimizer.add_expense("Alice", "entertainment", 60.0)
        self.optimizer.add_expense("Alice", "utilities", 50.0)
        over = self.optimizer.get_over_budget_categories()
        self.assertIn("groceries", over)
        self.assertIn("entertainment", over)
        self.assertNotIn("utilities", over)

    def test_remove_user_clears_their_expenses_from_total(self):
        self.optimizer.add_user("Alice")
        self.optimizer.add_user("Bob")
